#[cfg(test)]
mod property_tests {
    use super::*;
    use proptest::prelude::*;
    use serde_json::json;

    fn arb_value_space() -> BoxedStrategy<MockValueSpace> {
        prop_oneof![
            Just(MockValueSpace::FixedSet),
            Just(MockValueSpace::Autonomous),
            Just(MockValueSpace::Seeded),
            Just(MockValueSpace::LiveFirst),
        ]
        .boxed()
    }

    fn arb_json_value() -> BoxedStrategy<serde_json::Value> {
        prop_oneof![
            Just(json!(null)),
            any::<bool>().prop_map(|b| json!(b)),
            any::<i64>().prop_map(|n| json!(n)),
            ".*".prop_map(|s: String| json!(s)),
        ]
        .boxed()
    }

    fn arb_called_with_pattern() -> BoxedStrategy<CalledWithPattern> {
        proptest::collection::vec(arb_json_value(), 0..=4)
            .prop_map(|args| CalledWithPattern { args })
            .boxed()
    }

    fn arb_mock_expectation() -> BoxedStrategy<MockExpectation> {
        (
            proptest::collection::vec(arb_called_with_pattern(), 0..=3),
            0u32..100,
            0u32..100,
        )
            .prop_map(|(called_with, a, b)| {
                let (min_calls, max_calls) = if a <= b { (a, b) } else { (b, a) };
                MockExpectation {
                    called_with,
                    min_calls,
                    max_calls,
                }
            })
            .boxed()
    }

    fn arb_mock_fixture() -> BoxedStrategy<MockFixture> {
        (
            "[a-z][a-z0-9_.]{0,20}",
            arb_value_space(),
            proptest::collection::vec(arb_json_value(), 0..=3),
            proptest::option::of(Just(crate::types::TypeInfo::Unknown)),
            proptest::option::of(arb_mock_expectation()),
        )
            .prop_map(|(symbol, value_space, return_values, return_type, expectations)| {
                MockFixture {
                    symbol,
                    value_space,
                    return_values,
                    return_type,
                    expectations,
                }
            })
            .boxed()
    }

    proptest! {
        /// MockValueSpace round-trips through YAML.
        #[test]
        fn value_space_yaml_roundtrip(mode in arb_value_space()) {
            let yaml = serde_yaml::to_string(&mode).expect("serialize");
            let parsed: MockValueSpace = serde_yaml::from_str(&yaml).expect("deserialize");
            prop_assert_eq!(parsed, mode);
        }

        /// MockFixture round-trips through JSON (protocol boundary).
        #[test]
        fn fixture_json_roundtrip(fixture in arb_mock_fixture()) {
            let json = serde_json::to_string(&fixture).expect("serialize");
            let parsed: MockFixture = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(parsed.symbol, fixture.symbol);
            prop_assert_eq!(parsed.value_space, fixture.value_space);
            prop_assert_eq!(parsed.return_values.len(), fixture.return_values.len());
        }

        /// MockExpectation round-trips through JSON.
        #[test]
        fn expectation_json_roundtrip(exp in arb_mock_expectation()) {
            let json = serde_json::to_string(&exp).expect("serialize");
            let parsed: MockExpectation = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(parsed.min_calls, exp.min_calls);
            prop_assert_eq!(parsed.max_calls, exp.max_calls);
            prop_assert_eq!(parsed.called_with.len(), exp.called_with.len());
        }

        /// Type validation never panics on arbitrary fixtures.
        #[test]
        fn type_validation_never_panics(fixture in arb_mock_fixture()) {
            let config = MockFixtureConfig {
                global: ScopedMockFixtures {
                    fixtures: std::collections::HashMap::from([(
                        fixture.symbol.clone(),
                        fixture,
