//! User-supplied mock fixtures loaded from `.shatter/config.yaml`.
//!
//! Supports four value-space policies controlling how return values are selected:
//! - **FixedSet**: cycle through user-supplied values in order
//! - **Autonomous**: engine generates values freely (user supplies type hints only)
//! - **Seeded**: start from user values, then mutate/extend autonomously
//! - **LiveFirst**: try the real function first; fall back to mock on failure
//!
//! Fixtures scope to three levels (global, file, function) with innermost-wins
//! precedence. Post-execution expectations (`called_with`, `call_count`) are
//! validated after exploration completes.

use std::collections::HashMap;

use serde::{Deserialize, Serialize};
use serde_json::Value;

use crate::types::TypeInfo;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/// Default minimum call count expectation (no minimum).
pub const DEFAULT_MIN_CALL_COUNT: u32 = 0;

/// Default maximum call count expectation (unlimited).
pub const DEFAULT_MAX_CALL_COUNT: u32 = u32::MAX;

// ---------------------------------------------------------------------------
// MockValueSpace policy
// ---------------------------------------------------------------------------

/// Controls how mock return values are selected during exploration.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Cycle through user-supplied values in order.
    FixedSet,
    /// Engine generates values freely; user supplies type hints only.
    Autonomous,
    /// Start from user values, then mutate/extend autonomously.
    Seeded,
    /// Try the real function first; fall back to mock on failure.
    LiveFirst,
}

impl Default for MockValueSpace {
    fn default() -> Self {
        Self::FixedSet
    }
}

// ---------------------------------------------------------------------------
// Expectation types
// ---------------------------------------------------------------------------

/// Pattern matching an expected call's arguments.
///
/// Each element corresponds to a positional argument. `null` acts as a wildcard
/// matching any value.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct CalledWithPattern {
    /// Positional argument patterns. `null` means "any value".
    pub args: Vec<Value>,
}

/// Post-execution expectations for a mock.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MockExpectation {
    /// Expected call argument patterns. Empty means no argument expectations.
    #[serde(default)]
    pub called_with: Vec<CalledWithPattern>,

    /// Minimum number of calls expected.
    #[serde(default = "default_min_call_count")]
    pub min_calls: u32,

    /// Maximum number of calls expected (`u32::MAX` = unlimited).
    #[serde(default = "default_max_call_count")]
    pub max_calls: u32,
}

fn default_min_call_count() -> u32 {
    DEFAULT_MIN_CALL_COUNT
}

fn default_max_call_count() -> u32 {
    DEFAULT_MAX_CALL_COUNT
}

impl Default for MockExpectation {
    fn default() -> Self {
        Self {
            called_with: Vec::new(),
            min_calls: DEFAULT_MIN_CALL_COUNT,
            max_calls: DEFAULT_MAX_CALL_COUNT,
        }
    }
}

// ---------------------------------------------------------------------------
// MockFixture — a single mock definition
// ---------------------------------------------------------------------------

/// A user-defined mock fixture for a single symbol.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MockFixture {
    /// Fully qualified symbol name (e.g. `"db.query"`).
    pub symbol: String,

    /// How return values are selected.
    #[serde(default)]
    pub value_space: MockValueSpace,

    /// Pre-configured return values (required for `FixedSet`; optional seeds for `Seeded`).
    #[serde(default)]
    pub return_values: Vec<Value>,

    /// Expected return type — used for type validation and `Autonomous`/`Seeded` generation.
    #[serde(default)]
    pub return_type: Option<TypeInfo>,

    /// Post-execution expectations.
    #[serde(default)]
    pub expectations: Option<MockExpectation>,
}

// ---------------------------------------------------------------------------
// Scoped fixture collections
// ---------------------------------------------------------------------------

/// Mock fixtures at a single scope level.
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct ScopedMockFixtures {
    /// Fixtures keyed by symbol name.
    #[serde(default)]
    pub fixtures: HashMap<String, MockFixture>,
}

/// All user mock fixtures from config, organized by scope.
///
/// Resolution order: function > file > global (innermost wins).
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct MockFixtureConfig {
    /// Global fixtures applied to all functions.
    #[serde(default)]
    pub global: ScopedMockFixtures,

    /// File-scoped fixtures, keyed by file path pattern.
    #[serde(default)]
    pub files: HashMap<String, ScopedMockFixtures>,

    /// Function-scoped fixtures, keyed by `"file::function"` pattern.
    #[serde(default)]
    pub functions: HashMap<String, ScopedMockFixtures>,
}

// ---------------------------------------------------------------------------
// Type validation
// ---------------------------------------------------------------------------

/// A type mismatch found during fixture validation.
#[derive(Debug, Clone, PartialEq)]
pub struct TypeMismatch {
    /// The symbol whose return value is mismatched.
    pub symbol: String,
    /// Scope where the fixture was defined (e.g. "global", "file:src/auth.ts").
    pub scope: String,
    /// Index of the mismatched value in `return_values`.
    pub value_index: usize,
    /// The expected type from the fixture's `return_type`.
    pub expected_type: TypeInfo,
    /// Human-readable description of what was found.
    pub actual_description: String,
}

impl std::fmt::Display for TypeMismatch {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "mock '{}' ({}): return_values[{}] expected {:?} but got {}",
            self.symbol, self.scope, self.value_index, self.expected_type, self.actual_description
        )
    }
}

/// Validate that all return values in a fixture config match their declared types.
///
/// Returns all mismatches found (empty vec = valid). This runs at config load
/// time so users get feedback before exploration starts.
pub fn validate_fixture_types(config: &MockFixtureConfig) -> Vec<TypeMismatch> {
    let mut mismatches = Vec::new();

    validate_scoped_fixtures(&config.global, "global", &mut mismatches);

    for (file_pattern, scoped) in &config.files {
        validate_scoped_fixtures(scoped, &format!("file:{file_pattern}"), &mut mismatches);
    }

    for (fn_pattern, scoped) in &config.functions {
        validate_scoped_fixtures(scoped, &format!("function:{fn_pattern}"), &mut mismatches);
    }

    mismatches
}

fn validate_scoped_fixtures(
    scoped: &ScopedMockFixtures,
    scope: &str,
    mismatches: &mut Vec<TypeMismatch>,
) {
    for fixture in scoped.fixtures.values() {
        let Some(ref expected_type) = fixture.return_type else {
            continue;
        };

        for (i, value) in fixture.return_values.iter().enumerate() {
            if !value_matches_type(value, expected_type) {
                mismatches.push(TypeMismatch {
                    symbol: fixture.symbol.clone(),
                    scope: scope.to_string(),
                    value_index: i,
                    expected_type: expected_type.clone(),
                    actual_description: describe_json_value(value),
                });
            }
        }
    }
}

/// Check whether a JSON value is compatible with a TypeInfo.
///
/// Null is always accepted (nullable values are common in mocks).
/// Unknown type accepts anything. For structured types, checks recursively.
fn value_matches_type(value: &Value, expected: &TypeInfo) -> bool {
    if value.is_null() {
        return true;
    }

    match expected {
        TypeInfo::Int => value.is_i64() || value.is_u64(),
        TypeInfo::Float => value.is_number(),
        TypeInfo::Str => value.is_string(),
        TypeInfo::Bool => value.is_boolean(),
        TypeInfo::Array { element } => {
            value.as_array().is_some_and(|arr| {
                arr.iter().all(|v| value_matches_type(v, element))
            })
        }
        TypeInfo::Object { fields } => {
            value.as_object().is_some_and(|obj| {
                fields.iter().all(|(name, ty)| {
                    match obj.get(name) {
                        Some(v) => value_matches_type(v, ty),
                        None => true, // missing fields are OK (treated as null)
                    }
                })
            })
        }
        TypeInfo::Nullable { inner } => value_matches_type(value, inner),
        TypeInfo::Union { variants } => {
            variants.iter().any(|v| value_matches_type(value, v))
        }
        TypeInfo::Unknown | TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } => true,
    }
}

fn describe_json_value(value: &Value) -> String {
    match value {
        Value::Null => "null".to_string(),
        Value::Bool(_) => "boolean".to_string(),
        Value::Number(n) => {
            if n.is_i64() || n.is_u64() {
                "integer".to_string()
            } else {
                "float".to_string()
            }
        }
        Value::String(_) => "string".to_string(),
        Value::Array(_) => "array".to_string(),
        Value::Object(_) => "object".to_string(),
    }
}

// ---------------------------------------------------------------------------
// Fixture resolution
// ---------------------------------------------------------------------------

/// Resolve the effective mock fixture for a symbol, applying scope precedence.
///
/// Checks function scope first, then file scope, then global. Returns the
/// innermost match, or `None` if no fixture is defined for the symbol.
pub fn resolve_fixture(
    config: &MockFixtureConfig,
    file_path: &str,
    function_id: &str,
    symbol: &str,
) -> Option<MockFixture> {
    // Function scope: check "file::function" patterns
    for (pattern, scoped) in &config.functions {
        if pattern_matches_function(pattern, file_path, function_id) {
            if let Some(fixture) = scoped.fixtures.get(symbol) {
                return Some(fixture.clone());
            }
        }
    }

    // File scope: check file path patterns
    for (pattern, scoped) in &config.files {
        if file_path.contains(pattern) || pattern == file_path {
            if let Some(fixture) = scoped.fixtures.get(symbol) {
                return Some(fixture.clone());
            }
        }
    }

    // Global scope
    config.global.fixtures.get(symbol).cloned()
}

/// Check if a `"file::function"` pattern matches the given file and function.
fn pattern_matches_function(pattern: &str, file_path: &str, function_id: &str) -> bool {
    if let Some((file_part, fn_part)) = pattern.split_once("::") {
        (file_path.contains(file_part) || file_part == file_path)
            && (fn_part == function_id || fn_part == "*")
    } else {
        // No "::" separator — treat as function name only
        pattern == function_id
    }
}

// ---------------------------------------------------------------------------
// Expectation validation
// ---------------------------------------------------------------------------

/// Result of validating a mock expectation against actual call data.
#[derive(Debug, Clone, PartialEq)]
pub struct ExpectationViolation {
    pub symbol: String,
    pub kind: ViolationKind,
}

/// The kind of expectation violation.
#[derive(Debug, Clone, PartialEq)]
pub enum ViolationKind {
    /// Actual call count was below min_calls.
    TooFewCalls { expected_min: u32, actual: u32 },
    /// Actual call count exceeded max_calls.
    TooManyCalls { expected_max: u32, actual: u32 },
    /// A `called_with` pattern was never matched by any actual call.
    MissingCalledWith { pattern: CalledWithPattern },
}

impl std::fmt::Display for ExpectationViolation {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match &self.kind {
            ViolationKind::TooFewCalls { expected_min, actual } => {
                write!(
                    f,
                    "mock '{}': expected at least {} calls, got {}",
                    self.symbol, expected_min, actual
                )
            }
            ViolationKind::TooManyCalls { expected_max, actual } => {
                write!(
                    f,
                    "mock '{}': expected at most {} calls, got {}",
                    self.symbol, expected_max, actual
                )
            }
            ViolationKind::MissingCalledWith { pattern } => {
                write!(
                    f,
                    "mock '{}': expected call with args {:?} was never observed",
                    self.symbol, pattern.args
                )
            }
        }
    }
}

/// Validate mock expectations against actual call records.
///
/// `actual_calls` maps symbol to list of argument vectors observed during execution.
/// `actual_call_counts` maps symbol to total call count.
pub fn validate_expectations(
    fixtures: &[MockFixture],
    actual_calls: &HashMap<String, Vec<Vec<Value>>>,
    actual_call_counts: &HashMap<String, u32>,
) -> Vec<ExpectationViolation> {
    let mut violations = Vec::new();

    for fixture in fixtures {
        let Some(ref expectation) = fixture.expectations else {
            continue;
        };

        let count = actual_call_counts.get(&fixture.symbol).copied().unwrap_or(0);

        if count < expectation.min_calls {
            violations.push(ExpectationViolation {
                symbol: fixture.symbol.clone(),
                kind: ViolationKind::TooFewCalls {
                    expected_min: expectation.min_calls,
                    actual: count,
                },
            });
        }

        if count > expectation.max_calls {
            violations.push(ExpectationViolation {
                symbol: fixture.symbol.clone(),
                kind: ViolationKind::TooManyCalls {
                    expected_max: expectation.max_calls,
                    actual: count,
                },
            });
        }

        // Check called_with patterns
        let empty_calls = Vec::new();
        let calls = actual_calls.get(&fixture.symbol).unwrap_or(&empty_calls);

        for pattern in &expectation.called_with {
            let matched = calls.iter().any(|call_args| {
                args_match_pattern(call_args, &pattern.args)
            });
            if !matched {
                violations.push(ExpectationViolation {
                    symbol: fixture.symbol.clone(),
                    kind: ViolationKind::MissingCalledWith {
                        pattern: pattern.clone(),
                    },
                });
            }
        }
    }

    violations
}

/// Check if actual call arguments match a `called_with` pattern.
///
/// Each pattern element is matched positionally. `null` in the pattern acts
/// as a wildcard matching any value. Extra actual args are ignored.
fn args_match_pattern(actual: &[Value], pattern: &[Value]) -> bool {
    if actual.len() < pattern.len() {
        return false;
    }
    pattern.iter().enumerate().all(|(i, expected)| {
        if expected.is_null() {
            return true; // wildcard
        }
        actual.get(i).is_some_and(|actual_val| actual_val == expected)
    })
}

