            return_values: vec![json!({"rows": []})],
            return_type: None,
            expectations: None,
        };
        let fn_fixture = MockFixture {
            symbol: "db.query".to_string(),
            value_space: MockValueSpace::Seeded,
            return_values: vec![json!({"rows": [{"id": 1}]})],
            return_type: None,
            expectations: None,
        };

        let config = MockFixtureConfig {
            global: ScopedMockFixtures {
                fixtures: HashMap::from([("db.query".to_string(), global_fixture)]),
            },
            files: HashMap::new(),
            functions: HashMap::from([(
                "src/auth.ts::validate".to_string(),
                ScopedMockFixtures {
                    fixtures: HashMap::from([("db.query".to_string(), fn_fixture.clone())]),
                },
            )]),
        };

        let resolved = resolve_fixture(&config, "src/auth.ts", "validate", "db.query");
        assert_eq!(resolved, Some(fn_fixture));
    }

