    // -- Expectation validation --

    #[test]
    fn validate_expectations_passes_when_met() {
        let fixtures = vec![MockFixture {
            symbol: "db.query".to_string(),
            value_space: MockValueSpace::FixedSet,
            return_values: vec![json!(null)],
            return_type: None,
            expectations: Some(MockExpectation {
                called_with: vec![CalledWithPattern {
                    args: vec![json!("SELECT 1")],
                }],
                min_calls: 1,
                max_calls: 3,
            }),
        }];

        let actual_calls = HashMap::from([(
            "db.query".to_string(),
            vec![vec![json!("SELECT 1")], vec![json!("SELECT 2")]],
        )]);
        let actual_counts = HashMap::from([("db.query".to_string(), 2)]);

        let violations = validate_expectations(&fixtures, &actual_calls, &actual_counts);
        assert!(violations.is_empty());
    }

    #[test]
    fn validate_expectations_too_few_calls() {
        let fixtures = vec![MockFixture {
            symbol: "db.query".to_string(),
            value_space: MockValueSpace::FixedSet,
            return_values: vec![],
            return_type: None,
            expectations: Some(MockExpectation {
                called_with: vec![],
                min_calls: 3,
                max_calls: DEFAULT_MAX_CALL_COUNT,
            }),
        }];

        let violations = validate_expectations(&fixtures, &HashMap::new(), &HashMap::new());
        assert_eq!(violations.len(), 1);
        assert!(matches!(
            violations[0].kind,
            ViolationKind::TooFewCalls { expected_min: 3, actual: 0 }
        ));
    }

    #[test]
    fn validate_expectations_too_many_calls() {
        let fixtures = vec![MockFixture {
            symbol: "fn1".to_string(),
            value_space: MockValueSpace::FixedSet,
            return_values: vec![],
            return_type: None,
            expectations: Some(MockExpectation {
                called_with: vec![],
                min_calls: 0,
                max_calls: 2,
            }),
        }];

        let actual_counts = HashMap::from([("fn1".to_string(), 5)]);
        let violations = validate_expectations(&fixtures, &HashMap::new(), &actual_counts);
        assert_eq!(violations.len(), 1);
        assert!(matches!(
            violations[0].kind,
            ViolationKind::TooManyCalls { expected_max: 2, actual: 5 }
        ));
    }

    #[test]
    fn validate_expectations_missing_called_with() {
        let fixtures = vec![MockFixture {
            symbol: "fn1".to_string(),
            value_space: MockValueSpace::FixedSet,
            return_values: vec![],
            return_type: None,
            expectations: Some(MockExpectation {
                called_with: vec![CalledWithPattern {
                    args: vec![json!(42), json!("hello")],
                }],
                min_calls: 0,
                max_calls: DEFAULT_MAX_CALL_COUNT,
            }),
        }];

        // Calls happened, but not with the expected args
        let actual_calls = HashMap::from([(
            "fn1".to_string(),
            vec![vec![json!(99), json!("world")]],
        )]);
        let actual_counts = HashMap::from([("fn1".to_string(), 1)]);

        let violations = validate_expectations(&fixtures, &actual_calls, &actual_counts);
        assert_eq!(violations.len(), 1);
        assert!(matches!(
            violations[0].kind,
            ViolationKind::MissingCalledWith { .. }
        ));
    }

    #[test]
    fn called_with_null_acts_as_wildcard() {
        let fixtures = vec![MockFixture {
            symbol: "fn1".to_string(),
            value_space: MockValueSpace::FixedSet,
            return_values: vec![],
            return_type: None,
            expectations: Some(MockExpectation {
                called_with: vec![CalledWithPattern {
                    args: vec![json!(null), json!("exact")],
                }],
                min_calls: 0,
                max_calls: DEFAULT_MAX_CALL_COUNT,
            }),
        }];

        let actual_calls = HashMap::from([(
            "fn1".to_string(),
            vec![vec![json!("anything"), json!("exact")]],
        )]);
        let actual_counts = HashMap::from([("fn1".to_string(), 1)]);

        let violations = validate_expectations(&fixtures, &actual_calls, &actual_counts);
        assert!(violations.is_empty());
    }

