    #[test]
    fn args_match_pattern_exact() {
        assert!(args_match_pattern(
            &[json!(1), json!("a")],
            &[json!(1), json!("a")]
        ));
    }

    #[test]
    fn args_match_pattern_extra_args_ok() {
