    }

    #[test]
    fn args_match_pattern_wildcard_null() {
        assert!(args_match_pattern(
            &[json!(42), json!("hello")],
            &[json!(null), json!("hello")]
        ));
    }

    // -- pattern_matches_function --

    #[test]
    fn pattern_with_separator_matches() {
        assert!(pattern_matches_function(
            "src/auth.ts::validate",
            "src/auth.ts",
            "validate"
        ));
    }

    #[test]
    fn pattern_with_wildcard_function() {
        assert!(pattern_matches_function(
            "src/auth.ts::*",
            "src/auth.ts",
            "anyFunction"
        ));
    }

    #[test]
    fn pattern_without_separator() {
        assert!(pattern_matches_function("validate", "src/auth.ts", "validate"));
        assert!(!pattern_matches_function("validate", "src/auth.ts", "other"));
    }

    #[test]
    fn pattern_partial_file_match() {
        assert!(pattern_matches_function(
            "auth.ts::validate",
            "src/auth.ts",
